const now = new Date().toISOString();

function normalizePayload(payload) {
  if (Buffer.isBuffer(payload)) {
    payload = payload.toString('utf8');
  }
  if (typeof payload === 'string') {
    return JSON.parse(payload);
  }
  if (payload && typeof payload === 'object') {
    return payload;
  }
  throw new Error('payload must be JSON object or JSON string');
}

let body;
try {
  body = normalizePayload(msg.payload);
} catch (err) {
  const rejected = {
    topic: 'oncovax/demo/orchestration/status',
    payload: {
      contract_version: '1.0',
      status: 'rejected',
      source_topic: msg.topic,
      command_type: 'scenario/select',
      reason: err.message,
      received_at: now
    }
  };
  return [null, rejected];
}

const required = ['command_id', 'issued_at', 'scenario'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null || body[key] === '');
if (missing.length > 0) {
  return [null, {
    topic: 'oncovax/demo/orchestration/status',
    payload: {
      contract_version: '1.0',
      status: 'rejected',
      source_topic: msg.topic,
      command_type: 'scenario/select',
      reason: `missing fields: ${missing.join(', ')}`,
      received_at: now,
      command_id: body.command_id || null
    }
  }];
}

const accepted = {
  topic: 'oncovax/demo/orchestration/status',
  payload: {
    contract_version: '1.0',
    status: 'accepted',
    source_topic: msg.topic,
    command_type: 'scenario/select',
    command_id: body.command_id,
    issued_at: body.issued_at,
    scenario: body.scenario,
    received_at: now
  }
};
return [accepted, null];

